/**
 * E2e tests for category: conversion
 * Generated by html-to-markdown-e2e-generator — do not edit manually.
 */
import { describe, it, expect } from 'vitest';
import { convert } from '@kreuzberg/html-to-markdown';

describe('conversion', () => {
  it('blockquote_simple: Simple blockquote', () => {
    const html = `<blockquote><p>Quote text</p></blockquote>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('> Quote text');
  });

  it('bold_and_italic: Nested bold and italic', () => {
    const html = `<p><strong><em>both</em></strong></p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('***both***');
  });

  it('bold_strong: Strong tag converts to bold', () => {
    const html = `<p><strong>bold</strong></p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('**bold**');
  });

  it('code_block: Code block with language', () => {
    const html = `<pre><code class="language-python">print('hello')</code></pre>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('```python');
    expect(content).toContain('print(\'hello\')');
    expect(content).toContain('```');
  });

  it('heading_h1: H1 heading', () => {
    const html = `<h1>Heading 1</h1>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('# Heading 1');
  });

  it('heading_h2: H2 heading', () => {
    const html = `<h2>Heading 2</h2>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('## Heading 2');
  });

  it('heading_h3: H3 heading', () => {
    const html = `<h3>Heading 3</h3>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('### Heading 3');
  });

  it('heading_h4: H4 heading', () => {
    const html = `<h4>Heading 4</h4>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('#### Heading 4');
  });

  it('heading_h5: H5 heading', () => {
    const html = `<h5>Heading 5</h5>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('##### Heading 5');
  });

  it('heading_h6: H6 heading', () => {
    const html = `<h6>Heading 6</h6>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('###### Heading 6');
  });

  it('image_simple: Image with alt text', () => {
    const html = `<img src="photo.jpg" alt="A photo">`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('![A photo](photo.jpg)');
  });

  it('inline_code: Inline code', () => {
    const html = `<p>Use <code>console.log()</code> to debug</p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('`console.log()`');
  });

  it('italic_em: Em tag converts to italic', () => {
    const html = `<p><em>italic</em></p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('*italic*');
  });

  it('link_simple: Simple link', () => {
    const html = `<a href="https://example.com">Example</a>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('[Example](https://example.com)');
  });

  it('link_with_title: Link with title attribute', () => {
    const html = `<a href="https://example.com" title="Example Site">Example</a>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('[Example](https://example.com');
    expect(content).toContain('Example Site');
  });

  it('ordered_list: Ordered list', () => {
    const html = `<ol><li>First</li><li>Second</li><li>Third</li></ol>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('1. First');
    expect(content).toContain('2. Second');
    expect(content).toContain('3. Third');
  });

  it('simple_table: Simple table with header', () => {
    const html = `<table><thead><tr><th>Name</th><th>Age</th></tr></thead><tbody><tr><td>Alice</td><td>30</td></tr></tbody></table>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('Name');
    expect(content).toContain('Age');
    expect(content).toContain('Alice');
    expect(content).toContain('30');
    expect(content).toContain('|');
    expect(content).toContain('---');
  });

  it('unordered_list: Unordered list', () => {
    const html = `<ul><li>Item 1</li><li>Item 2</li><li>Item 3</li></ul>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content).toContain('- Item 1');
    expect(content).toContain('- Item 2');
    expect(content).toContain('- Item 3');
  });

});
